#include <bits/stdc++.h>
using namespace std;
typedef long long ll;
const int N=3e5+5;
int n,s;
ll c[N],t[N],f[N];
int q[N];
int main(){
    scanf("%d%d",&n,&s);
    for(int i=1;i<=n;i++){
        scanf("%lld%lld",&t[i],&c[i]);
        c[i]+=c[i-1],t[i]+=t[i-1];
    }
    int hh=0,tt=0;
    q[0]=0;
    for(int i=1;i<=n;i++){
        int l=hh,r=tt;
        while(l<r){
            int mid=l+r>>1;
            if(f[q[mid+1]]-f[q[mid]]>(t[i]+s)*(c[q[mid+1]]-c[q[mid]]))
                r=mid;
            else
                l=mid+1;
        }
        int j=q[r];//要套q!
        f[i]=f[j]+t[i]*(c[i]-c[j])+s*(c[n]-c[j]);
        while(hh<tt && (f[q[tt]]-f[q[tt-1]])*(c[i]-c[q[tt]])>=(f[i]-f[q[tt]])*(c[q[tt]]-c[q[tt-1]]))
            tt--;
        q[++tt]=i;
    }
    printf("%lld",f[n]);
    return 0;
}
